type Intel_RAPL_Data is
    record
        psys : Long_Float;
        pkg : Long_Float;
        dram : Long_Float;

        total_energy : Long_Float := 0.0;

        psys_supported : Boolean := False;
        pkg_supported : Boolean := False;
        dram_supported : Boolean := False;
        pkg_max_energy_range : Long_Float := 0.0;
        psys_max_energy_range : Long_Float := 0.0;
        dram_max_energy_range : Long_Float := 0.0;
    end record;
